import React, { useMemo } from "react";

/** ====== Imports ======
 * Put one file per condition+time in EACH folder (desktop & mobile) with the SAME names:
 *   clearday.mp4, clearnight.mp4
 *   cloudyday.mp4, cloudynight.mp4
 *   rainday.mp4,  rainnight.mp4
 *   snowday.mp4,  snownight.mp4
 *   thunderstormday.mp4, thunderstormnight.mp4
 *   fogday.mp4,   fognight.mp4
 *
 * Folder structure (example):
 * src/assets/overlays/desktop/clearday.mp4
 * src/assets/overlays/mobile/clearday.mp4
 */

// Desktop
import clearDayDesktop from "../assets/overlays/desktop/clearday.mp4";
import clearNightDesktop from "../assets/overlays/desktop/clearnight.mp4";
import cloudyDayDesktop from "../assets/overlays/desktop/cloudyday.mp4";
import cloudyNightDesktop from "../assets/overlays/desktop/cloudynight.mp4";
import rainDayDesktop from "../assets/overlays/desktop/rainday.mp4";
import rainNightDesktop from "../assets/overlays/desktop/rainnight.mp4";
import snowDayDesktop from "../assets/overlays/desktop/snowday.mp4";
import snowNightDesktop from "../assets/overlays/desktop/snownight.mp4";
import thunderDayDesktop from "../assets/overlays/desktop/thunderstormday.mp4";
import thunderNightDesktop from "../assets/overlays/desktop/thunderstormnight.mp4";
import fogDayDesktop from "../assets/overlays/desktop/fogday.mp4";
import fogNightDesktop from "../assets/overlays/desktop/fognight.mp4";

// Mobile
import clearDayMobile from "../assets/overlays/mobile/clearday.mp4";
import clearNightMobile from "../assets/overlays/mobile/clearnight.mp4";
import cloudyDayMobile from "../assets/overlays/mobile/cloudyday.mp4";
import cloudyNightMobile from "../assets/overlays/mobile/cloudynight.mp4";
import rainDayMobile from "../assets/overlays/mobile/rainday.mp4";
import rainNightMobile from "../assets/overlays/mobile/rainnight.mp4";
import snowDayMobile from "../assets/overlays/mobile/snowday.mp4";
import snowNightMobile from "../assets/overlays/mobile/snownight.mp4";
import thunderDayMobile from "../assets/overlays/mobile/thunderstormday.mp4";
import thunderNightMobile from "../assets/overlays/mobile/thunderstormnight.mp4";
import fogDayMobile from "../assets/overlays/mobile/fogday.mp4";
import fogNightMobile from "../assets/overlays/mobile/fognight.mp4";

/** Normalize input into one of: clear | cloudy | rain | snow | thunder | fog */
function normalizeCondition(cond) {
  let s = "";
  if (typeof cond === "string") s = cond;
  else if (cond && typeof cond === "object") s = cond.main || cond.description || "";
  s = String(s).toLowerCase();

  if (!s) return "clear";
  if (s.includes("thunder") || s.includes("tornado") || s.includes("squall")) return "thunder";
  if (s.includes("drizzle") || s.includes("rain")) return "rain";
  if (s.includes("snow") || s.includes("sleet") || s.includes("hail")) return "snow";
  if (s.includes("cloud")) return "cloudy";
  if (s.includes("mist") || s.includes("fog") || s.includes("haze") || s.includes("smoke")) return "fog";
  return "clear";
}

/** Map: condition -> { day: {desktop, mobile}, night: {desktop, mobile} } */
const VIDEO_MAP = {
  clear: {
    day:   { desktop: clearDayDesktop,   mobile: clearDayMobile },
    night: { desktop: clearNightDesktop, mobile: clearNightMobile },
  },
  cloudy: {
    day:   { desktop: cloudyDayDesktop,   mobile: cloudyDayMobile },
    night: { desktop: cloudyNightDesktop, mobile: cloudyNightMobile },
  },
  rain: {
    day:   { desktop: rainDayDesktop,   mobile: rainDayMobile },
    night: { desktop: rainNightDesktop, mobile: rainNightMobile },
  },
  snow: {
    day:   { desktop: snowDayDesktop,   mobile: snowDayMobile },
    night: { desktop: snowNightDesktop, mobile: snowNightMobile },
  },
  thunder: {
    day:   { desktop: thunderDayDesktop,   mobile: thunderDayMobile },
    night: { desktop: thunderNightDesktop, mobile: thunderNightMobile },
  },
  fog: {
    day:   { desktop: fogDayDesktop,   mobile: fogDayMobile },
    night: { desktop: fogNightDesktop, mobile: fogNightMobile },
  },
};

export default function WeatherOverlay({
  condition,           // string or object ({main, description})
  isDay = true,        // boolean
  device = "desktop",  // "desktop" | "mobile"
  className = "",
  opacity = 0.85,      // tweak overlay strength
}) {
  const key = useMemo(() => normalizeCondition(condition), [condition]);
  const dayKey = isDay ? "day" : "night";
  const devKey = device === "mobile" ? "mobile" : "desktop";
  const src = VIDEO_MAP[key]?.[dayKey]?.[devKey];

  if (!src) return null;

  return (
    <div className={`fixed inset-0 -z-10 pointer-events-none ${className}`} aria-hidden="true">
      <video
        src={src}
        autoPlay
        muted
        loop
        playsInline
        className="w-full h-full object-cover"
        style={{ opacity }}
      />
    </div>
  );
}
